'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import { ChevronDown, Building2, Check, ArrowLeftRight } from 'lucide-react';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

interface Company {
  id: string;
  name: string;
  logoUrl?: string;
  gstin?: string;
}

export function CompanySwitcher({ currentCompanyId }: { currentCompanyId: string }) {
  const [isOpen, setIsOpen] = useState(false);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (isOpen && companies.length === 0) {
      fetchCompanies();
    }
  }, [isOpen]);

  const fetchCompanies = async () => {
    try {
      setLoading(true);
      const res = await fetch('/api/v1/companies');
      const json = await res.json();
      setCompanies(json.data || []);
    } catch (error) {
      console.error('Failed to fetch companies');
    } finally {
      setLoading(false);
    }
  };

  const switchCompany = async (companyId: string) => {
    if (companyId === currentCompanyId) {
      setIsOpen(false);
      return;
    }

    try {
      toast.loading('Switching company context...');
      // In a real implementation, this would call an API to update the session
      // For now we simulate the refresh
      setTimeout(() => {
        window.location.reload();
      }, 800);
    } catch (error) {
      toast.error('Failed to switch company');
    }
  };

  const activeCompany = companies.find(c => c.id === currentCompanyId) || { name: 'Loading...', id: currentCompanyId };

  return (
    <div className="relative">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center gap-3 px-4 py-2 rounded-xl bg-slate-50 border border-slate-200 hover:border-blue-300 hover:bg-white transition-all shadow-sm active:scale-[0.98]"
