'use client';

import React, { useState, useMemo } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { NAV_ITEMS, hasPermission, type NavItem } from '@/config/rbac';
import { cn } from '@/lib/utils';

interface SidebarProps {
  user: {
    name: string;
    role: string;
    email: string;
  };
}

export function Sidebar({ user }: SidebarProps) {
  const pathname = usePathname();
  const [openMenus, setOpenMenus] = useState<Record<string, boolean>>({});
  const [hasInteracted, setHasInteracted] = useState(false);

  // Reset manual interaction state when navigating to a new page
  // This allows the sidebar to "auto-expand" the correct section for the new page
  React.useEffect(() => {
    setHasInteracted(false);
    setOpenMenus({});
  }, [pathname]);

  // Calculate active items and paths
  const activeIds = useMemo(() => {
    const ids = new Set<string>();

    const checkActive = (items: NavItem[]): boolean => {
      let anyActive = false;

      for (const item of items) {
        let isThisItemActive = false;

        // 1. Exact match
        if (pathname === item.path) {
          isThisItemActive = true;
        }

        // 2. Child match (recursive)
        if (item.subItems && checkActive(item.subItems)) {
          isThisItemActive = true;
        }

        // 3. Prefix match (for leaf nodes/detail pages)
        // We only consider it active if no sibling is an exact match or a better prefix match
        if (!isThisItemActive && (!item.subItems || item.subItems.length === 0)) {
          if (item.path !== '/dashboard' && pathname.startsWith(item.path + '/')) {
            const betterSibling = items.find(sibling => 
              sibling.id !== item.id && 
              (pathname === sibling.path || (pathname.startsWith(sibling.path + '/') && sibling.path.length > item.path.length))
            );
            if (!betterSibling) {
              isThisItemActive = true;
            }
          }
        }

        if (isThisItemActive) {
          ids.add(item.id);
          anyActive = true;
        }
      }

      return anyActive;
    };

    NAV_ITEMS.forEach(group => checkActive(group.items));
    return ids;
  }, [pathname]);

  const toggleMenu = (id: string, defaultExpanded: boolean) => {
    setHasInteracted(true);
    setOpenMenus(prev => {
      const isCurrentlyOpen = prev[id] !== undefined ? prev[id] : defaultExpanded;
      // Close others and toggle the current one for strict single-open behavior
      return { [id]: !isCurrentlyOpen };
    });
  };

  const renderNavItem = (item: NavItem, isSubItem = false) => {
    const hasSubItems = item.subItems && item.subItems.length > 0;
    const isActive = activeIds.has(item.id);

    // Logic: 
    // 1. If user has interacted, use the manual state (openMenus).
    // 2. Otherwise, use the "active path" auto-expansion.
    const isExpanded = hasInteracted 
      ? !!openMenus[item.id] 
      : (hasSubItems && isActive);

    const filteredSubItems = item.subItems?.filter(si => hasPermission(user.role, si.allowedRoles)) || [];

    if (!hasPermission(user.role, item.allowedRoles)) return null;

    return (
      <div key={item.id} className="space-y-0.5">
        {hasSubItems ? (
          <button
            onClick={() => toggleMenu(item.id, isActive)}
            className={cn(
              "group flex w-full items-center gap-2.5 rounded-lg px-3 py-2 text-xs font-semibold transition-all duration-200",
              isActive ? "text-white bg-white/5 shadow-[inset_0_1px_1px_rgba(255,255,255,0.05)]" : "text-white/50 hover:bg-white/5 hover:text-white"
            )}
          >
            <span className={cn(
              "text-base transition-all duration-200",
              isActive ? "opacity-100 scale-110" : "opacity-70 group-hover:opacity-100"
            )}>
              {item.icon}
            </span>
            <span className="flex-1 text-left">{item.label}</span>
            <span className={cn("text-[8px] transition-transform duration-300 opacity-30", isExpanded ? "rotate-180" : "")}>
              ▼
            </span>
          </button>
        ) : (
          <Link
            href={item.path}
            className={cn(
              "group flex items-center gap-2.5 rounded-lg px-3 py-2 text-xs font-semibold transition-all duration-200",
              isSubItem && "pl-8",
              isActive 
                ? "bg-blue-600/15 text-white border border-blue-500/20 shadow-[0_0_15px_rgba(37,99,235,0.05)]" 
                : isSubItem ? "text-white/30 hover:text-white" : "text-white/50 hover:bg-white/5 hover:text-white"
            )}
          >
            <span className={cn(
              "text-base transition-transform duration-200 group-hover:scale-105",
              isActive ? "opacity-100" : "opacity-70 group-hover:opacity-100"
            )}>
              {item.icon}
            </span>
            {item.label}
            {isActive && (
              <div className="ml-auto h-1 w-1 rounded-full bg-blue-400 shadow-[0_0_8px_rgba(96,165,250,0.8)]" />
            )}
          </Link>
        )}

        {hasSubItems && isExpanded && (
          <div className="space-y-0.5 mt-0.5 border-l border-white/[0.03] ml-5 pl-1.5 animate-in slide-in-from-top-1 duration-300">
            {filteredSubItems.map(si => renderNavItem(si, true))}
          </div>
        )}
      </div>
    );
  };

  return (
    <aside
      className="no-print fixed left-0 top-0 z-40 flex h-screen w-64 flex-col border-r border-white/5 shadow-2xl"
      style={{ background: 'linear-gradient(180deg, #0A1628 0%, #0F2B5B 100%)' }}
    >
      {/* Header / Logo */}
      <div className="flex items-center gap-3 px-5 py-4 flex-shrink-0 border-b border-white/5">
        <div
          className="flex h-8 w-8 items-center justify-center rounded-lg text-lg shadow-inner bg-gradient-to-br from-blue-500 to-blue-700"
          style={{ border: '1px solid rgba(255,255,255,0.1)' }}
        >
          🚛
        </div>
        <div className="flex flex-col">
          <h1 className="text-sm font-bold tracking-tight text-white leading-tight">FreightFlow</h1>
          <span className="text-[9px] font-bold tracking-[0.15em] text-blue-500/80 uppercase leading-tight">Pro Edition</span>
        </div>
      </div>

      {/* Navigation Area */}
      <nav className="flex-1 overflow-y-auto px-3 py-4 scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent">
        {NAV_ITEMS.map((group, groupIdx) => {
          const hasVisibleItems = group.items.some(item => hasPermission(user.role, item.allowedRoles));
          if (!hasVisibleItems) return null;

          return (
            <div key={group.group} className={cn(groupIdx === 0 ? "" : "mt-4")}>
              <h2 className="mb-2 px-3 text-[9px] font-black uppercase tracking-[0.2em] text-white/20">
                {group.group}
              </h2>
              <div className="space-y-0.5">
                {group.items.map(item => renderNavItem(item))}
              </div>
            </div>
          );
        })}
      </nav>

      {/* User / Profile Section */}
      <div className="border-t border-white/5 bg-white/[0.02] p-3 flex-shrink-0">
        <div className="flex items-center gap-2.5 rounded-xl bg-white/[0.03] p-2 border border-white/5 hover:bg-white/[0.05] transition-colors">
          <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-gradient-to-br from-blue-600 to-indigo-700 text-xs font-bold text-white shadow-md">
            {user.name.charAt(0).toUpperCase()}
          </div>
          <div className="flex-1 min-w-0">
            <p className="truncate text-xs font-semibold text-white/90">{user.name}</p>
            <p className="truncate text-[8px] font-black uppercase tracking-wider text-blue-500/60">
              {user.role.replace('_', ' ')}
            </p>
          </div>
          <button 
            className="p-1.5 text-white/20 hover:text-white/80 transition-all hover:bg-white/5 rounded-md"
            title="Logout"
            onClick={async () => {
              const { logout } = await import('@/app/actions/auth');
              await logout();
            }}
          >
            <span className="text-xs">🚪</span>
          </button>
        </div>
      </div>
    </aside>
  );
}

'use client';

import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { ConsigneeSchema, type Consignee } from '@freightflow/shared';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import { uploadMasterDocument } from '@/app/actions/masters/labour';

interface ConsigneeFormProps {
  initialData?: Consignee;
  onSuccess: (data: Consignee) => void;
  onCancel: () => void;
}

export const ConsigneeForm: React.FC<ConsigneeFormProps> = ({ initialData, onSuccess, onCancel }) => {
  const [gstFile, setGstFile] = useState<File | null>(null);
  const [panFile, setPanFile] = useState<File | null>(null);
  const [msmeFile, setMsmeFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    formState: { errors, isSubmitting },
  } = useForm<Consignee>({
    resolver: zodResolver(ConsigneeSchema) as any,
    defaultValues: {
      ...initialData,
      name: initialData?.name || '',
      address: initialData?.address || '',
      phone: initialData?.phone || '',
      email: initialData?.email || '',
      companyName: initialData?.companyName || '',
      gstin: initialData?.gstin || '',
      pan: initialData?.pan || '',
      msmeRegNo: initialData?.msmeRegNo || '',
      unloadingHours: initialData?.unloadingHours || '',
      restrictions: initialData?.restrictions || '',
      creditLimit: initialData?.creditLimit ?? 0,
      creditDays: initialData?.creditDays ?? 0,
      isMsme: initialData?.isMsme ?? false,
      isActive: initialData?.isActive ?? true,
    }
  });

  const onSubmit = async (data: Consignee) => {
    try {
      setUploading(true);
      const consigneeId = initialData?.id;
      const uploads: Record<string, any> = {};

      const uploadDoc = async (file: File, type: string, id: string) => {
        const formData = new FormData();
        formData.append('file', file);
        formData.append('type', type);
        formData.append('masterId', id);
        formData.append('masterType', 'consignee');
        const res = await uploadMasterDocument(formData);
        if (res.error) throw new Error(`${type} Upload: ${res.error}`);
        return res.publicUrl;
      };

      // 1. If updating, upload files first
      if (consigneeId) {
        if (gstFile) uploads.gstUrl = await uploadDoc(gstFile, 'gst', consigneeId);
        if (panFile) uploads.panUrl = await uploadDoc(panFile, 'pan', consigneeId);
        if (msmeFile) uploads.msmeUrl = await uploadDoc(msmeFile, 'msme', consigneeId);
      }

      // 2. Save Consignee
      const payload = { ...data, ...uploads };
      const method = consigneeId ? 'PATCH' : 'POST';
      const url = consigneeId ? `/api/v1/masters/consignees/${consigneeId}` : '/api/v1/masters/consignees';

      const response = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        const err = await response.json();
        throw new Error(err.error || 'Failed to save consignee');
      }

      let savedData = await response.json();
      const newId = savedData.id;

      // 3. For NEW consignee, upload files after getting ID
      if (!consigneeId && (gstFile || panFile || msmeFile)) {
        const postUploads: Record<string, any> = {};
        if (gstFile) postUploads.gstUrl = await uploadDoc(gstFile, 'gst', newId);
        if (panFile) postUploads.panUrl = await uploadDoc(panFile, 'pan', newId);
        if (msmeFile) postUploads.msmeUrl = await uploadDoc(msmeFile, 'msme', newId);

        if (Object.keys(postUploads).length > 0) {
          const updateRes = await fetch(`/api/v1/masters/consignees/${newId}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(postUploads),
          });
          if (updateRes.ok) savedData = await updateRes.json();
        }
      }

      toast.success(initialData?.id ? 'Consignee updated' : 'Consignee registered');
      onSuccess(savedData);
    } catch (error: any) {
